const staticData = $getWorkflowStaticData('global');

const sqlResults =  $input.all();
const jsonResults = sqlResults.map(item => item.json);
const sqlquery = $('If').first().json.safeSQL

const preview = jsonResults.slice(0, 10);

const formattedTable = preview.map((row, i) => {
  const line = Object.entries(row)
    .map(([key, val]) => `| ${key} | ${val} |`)
    .join('\n');
  return `🔹 Ligne ${i + 1} :\n${line}`;
}).join('\n\n');

const resultJson = JSON.stringify(jsonResults, null, 2);

const prompt = `
Tu es un expert en bases de données SQL, spécialisé dans l’analyse de requêtes et l’interprétation de leurs résultats dans un contexte métier.

Je vais te fournir :
- Une requête SQL,
- Le résultat de son exécution (au format JSON),
- Ainsi qu’un aperçu des 10 premières lignes sous forme lisible.

Ta mission est d'expliquer **en français**, de manière claire, concise et accessible, les éléments suivants :
1. **La fonction de la requête** : Que cherche-t-elle à extraire ou à vérifier ?
2. **L’interprétation des résultats** : Quelle est la signification des lignes retournées dans le contexte métier ? Que peut-on en déduire ou conclure ?
3. **Aperçu des données** : Affiche **toujours** l'extrait lisible fourni (même s’il est vide), afin que l'utilisateur visualise les lignes concernées. Ne fais **aucune supposition** en cas d'absence de résultats. Si aucune donnée n’est retournée, indique-le explicitement et explique ce que cela peut signifier.

---
 **Affiche toujours les données fournies**, même si le tableau est vide ou peu rempli. Ne fais aucune supposition en l’absence de résultats. Si aucune donnée n’est retournée, indique-le clairement et explique ce que cela implique.

 **requete resultat** :
 ${sqlquery}

 **Aperçu des 10 premières lignes du résultat** :
${formattedTable}

 **Résultat complet (JSON)** :
${resultJson}

---

`;


return [
  {
    json: {
      prompt
    }
  }
];

const queries = $input.all();

const forbidden = ["drop", "delete", "update", "insert", "alter", "exec", "truncate", "create", "grant"];

const structuredQueries = queries.map((item, index) => {
  const query = item.json.query;
  const lowerQuery = query.toLowerCase();

  if (forbidden.some(keyword => lowerQuery.includes(keyword))) {
    throw new Error(`Rejected unsafe SQL query at index ${index + 1}.`);
  }

  return {
    json: {
      queryId: index + 1,
      safeSQL: query.trim()
    }
  };
});

return structuredQueries;

const rawSql = $input.first().json.output;

const queries = rawSql
  .split(";")
  .map(q => 
    q.trim()
     .replace(/^```sql\s*/, '')   // Supprime le début ```sql (optionnel)
     .replace(/\s*```$/, '')      
     .replace(/`/g, '')           
  )
  .filter(q => q.length > 10);    

return queries.map(query => ({ json: { query } }));

const sqlResults = $input.all();

/** @type {Record<string, { queryText: string, rows: any[] }>} */
const groupedResults = {};

sqlResults.forEach((item, index) => {
  const data = item.json;
  const queryId = String(data.queryId || `query_${index + 1}`);
  const queryText = data.safeSQL || data.query || '-- Requête SQL non disponible --';

  if (!groupedResults[queryId]) {
    groupedResults[queryId] = {
      queryText,
      rows: []
    };
  }

  // Copy only data fields (excluding query info)
  const row = {};
  for (const key in data) {
    if (!['queryId', 'query', 'safeSQL'].includes(key)) {
      row[key] = data[key];
    }
  }

  groupedResults[queryId].rows.push(row);
});

const allSections = [];

for (const queryId in groupedResults) {
  const group = groupedResults[queryId];
  const previewRows = group.rows.slice(0, 10);

  const formattedTable = previewRows.length > 0
    ? previewRows.map((row, i) => {
        const lines = [];
        for (const key in row) {
          lines.push(`| ${key} | ${row[key]} |`);
        }
        return `🔹 Ligne ${i + 1} :\n${lines.join('\n')}`;
      }).join('\n\n')
    : "_Aucune ligne retournée_";

  const resultJson = JSON.stringify(group.rows, null, 2);

  allSections.push(`
============================
🆔 **Requête SQL [${queryId}]**
\`\`\`sql
${group.queryText}
\`\`\`

📊 **Aperçu des 10 premières lignes**
${formattedTable}

🗃️ **Résultat complet (JSON)**
\`\`\`json
${resultJson}
\`\`\`

🎯 Ta mission est d'expliquer **en français**, clairement et simplement :
1. La fonction de cette requête : que cherche-t-elle à extraire ou vérifier ?
2. L’interprétation des résultats dans un contexte métier.
3. Ce que l'on peut conclure ou expliquer si aucun résultat n’est retourné.
`);
}

const prompt = `
Tu es un expert en bases de données SQL, spécialisé dans l’analyse de requêtes et l’interprétation métier.

Je vais te fournir plusieurs requêtes SQL et leurs résultats. Pour chacune, explique clairement sa fonction, interprète les résultats, et affiche toujours l’aperçu même s’il est vide.

** Sois synthétique dans tes explications. Va à l’essentiel. Utilise des phrases courtes et évite les redites. **
---

${allSections.join('\n\n')}
`;

return [
  {
    json: {
      prompt
    }
  }
];
